#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

const int TILE_SIZE = 32;

// Helper function for explicit, documented ceiling division
__device__ __host__ __forceinline__ int ceil_div(int numerator, int denominator) {
    return (numerator + denominator - 1) / denominator;  // CRITICAL: integer ceiling division
}

__global__ void matmul_transpose_kernel(
    const float* A,  // shape: [K, M]
    const float* B,  // shape: [K, N]
    float* C,        // shape: [M, N]
    int M, int K, int N) {

    // Shared memory for tiles
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    // Row and column of C to compute
    int row = by * TILE_SIZE + ty;
    int col = bx * TILE_SIZE + tx;

    float sum = 0.0f;

    // Compute tile count once with explicit, named function
    int num_tiles = ceil_div(K, TILE_SIZE);
    // Safety: ensure loop bound is non-negative
    if (num_tiles < 0) return;

    // Loop over tiles
    for (int t = 0; t < num_tiles; ++t) {
        // Load A tile (transposed access: A[K][M] -> As[M][K])
        int A_row = t * TILE_SIZE + tx;
        int A_col = row;
        if (A_row < K && A_col < M) {
            As[ty][tx] = A[A_row * M + A_col];  // A is stored as [K][M]
        } else {
            As[ty][tx] = 0.0f;
        }

        // Load B tile
        int B_row = t * TILE_SIZE + ty;
        int B_col = col;
        if (B_row < K && B_col < N) {
            Bs[ty][tx] = B[B_row * N + B_col];  // B is stored as [K][N]
        } else {
            Bs[ty][tx] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    // Write result
    if (row < M && col < N) {
        C[row * N + col] = sum;
    }
}

torch::Tensor matmul_transpose_cuda(torch::Tensor A, torch::Tensor B) {
    // A: [K, M], B: [K, N]
    int K = A.size(0);
    int M = A.size(1);
    int N = B.size(1);

    // Validate dimensions (defensive check)
    assert(K > 0 && M > 0 && N > 0 && "Dimensions must be positive");

    // Output: [M, N]
    auto C = torch::zeros({M, N}, A.options());

    // Configure grid and block dimensions using same ceiling division
    dim3 block(TILE_SIZE, TILE_SIZE);
    dim3 grid(ceil_div(N, TILE_SIZE), ceil_div(M, TILE_SIZE));

    // Launch kernel
    matmul_transpose_kernel<<<grid, block>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        M, K, N
    );

    return C;
}
